import{_ as o,o as t,c as d,ae as a}from"./chunks/framework.C7FLYIpo.js";const u=JSON.parse('{"title":"엘리베이티드 모드","description":"엘리베이티드 exec 모드: 샌드박스 처리된 에이전트에서 샌드박스 외부의 명령 실행","frontmatter":{"title":"엘리베이티드 모드","description":"엘리베이티드 exec 모드: 샌드박스 처리된 에이전트에서 샌드박스 외부의 명령 실행"},"headers":[],"relativePath":"tools/elevated.md","filePath":"tools/elevated.md","lastUpdated":null}'),l={name:"tools/elevated.md"};function c(r,e,n,s,i,h){return t(),d("div",null,[...e[0]||(e[0]=[a(`<h1 id="엘리베이티드-모드" tabindex="-1">엘리베이티드 모드 <a class="header-anchor" href="#엘리베이티드-모드" aria-label="Permalink to &quot;엘리베이티드 모드&quot;">​</a></h1><p>에이전트가 샌드박스 내부에서 실행되면 <code>exec</code> 명령이 샌드박스 환경에 제한됩니다. <strong>엘리베이티드 모드</strong>는 에이전트가 샌드박스를 벗어나 대신 구성 가능한 승인 게이트로 외부에서 명령을 실행할 수 있게 합니다.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>엘리베이티드 모드는 에이전트가 <strong>샌드박스 처리된</strong> 경우에만 동작을 변경합니다. 샌드박스 처리되지 않은 에이전트의 경우 exec는 이미 호스트에서 실행됩니다.</p></div><h2 id="지시어" tabindex="-1">지시어 <a class="header-anchor" href="#지시어" aria-label="Permalink to &quot;지시어&quot;">​</a></h2><p>슬래시 커맨드로 세션별 엘리베이티드 모드를 제어합니다:</p><table tabindex="0"><thead><tr><th>지시어</th><th>수행 내용</th></tr></thead><tbody><tr><td><code>/elevated on</code></td><td>구성된 호스트 경로에서 샌드박스 외부에서 실행, 승인 유지</td></tr><tr><td><code>/elevated ask</code></td><td><code>on</code>과 동일 (별칭)</td></tr><tr><td><code>/elevated full</code></td><td>구성된 호스트 경로에서 샌드박스 외부에서 실행 및 승인 건너뛰기</td></tr><tr><td><code>/elevated off</code></td><td>샌드박스 제한 실행으로 복귀</td></tr></tbody></table><p><code>/elev on|off|ask|full</code>로도 사용 가능합니다.</p><p>인수 없이 <code>/elevated</code>를 보내면 현재 레벨을 확인합니다.</p><h2 id="작동-방식" tabindex="-1">작동 방식 <a class="header-anchor" href="#작동-방식" aria-label="Permalink to &quot;작동 방식&quot;">​</a></h2><ol><li><p><strong>가용성 확인</strong></p><p>엘리베이티드가 설정에서 활성화되어 있고 발신자가 허용 목록에 있어야 합니다:</p><pre><code>\`\`\`json5
{
  tools: {
    elevated: {
      enabled: true,
      allowFrom: {
        discord: [&quot;user-id-123&quot;],
        whatsapp: [&quot;+15555550123&quot;],
      },
    },
  },
}
\`\`\`
</code></pre></li><li><p><strong>레벨 설정</strong></p></li></ol><p>지시어 전용 메시지를 보내 세션 기본값을 설정합니다:</p><pre><code>   \`\`\`
   /elevated full
   \`\`\`

   또는 인라인으로 사용합니다 (해당 메시지에만 적용):

   \`\`\`
   /elevated on run the deployment script
   \`\`\`
</code></pre><ol start="3"><li><strong>샌드박스 외부에서 명령 실행</strong></li></ol><p>엘리베이티드가 활성화되면 <code>exec</code> 호출이 샌드박스를 떠납니다. 기본적으로 유효 호스트는 <code>gateway</code>이고, 구성된/세션 exec 대상이 <code>node</code>인 경우 <code>node</code>입니다. <code>full</code> 모드에서는 exec 승인이 건너뛰어집니다. <code>on</code>/<code>ask</code> 모드에서는 구성된 승인 규칙이 여전히 적용됩니다.</p><h2 id="해결-순서" tabindex="-1">해결 순서 <a class="header-anchor" href="#해결-순서" aria-label="Permalink to &quot;해결 순서&quot;">​</a></h2><ol><li><strong>인라인 지시어</strong> 메시지에서 (해당 메시지에만 적용)</li><li><strong>세션 재정의</strong> (지시어 전용 메시지를 보내 설정)</li><li><strong>전역 기본값</strong> (설정의 <code>agents.defaults.elevatedDefault</code>)</li></ol><h2 id="가용성-및-허용-목록" tabindex="-1">가용성 및 허용 목록 <a class="header-anchor" href="#가용성-및-허용-목록" aria-label="Permalink to &quot;가용성 및 허용 목록&quot;">​</a></h2><ul><li><strong>전역 게이트</strong>: <code>tools.elevated.enabled</code> (반드시 <code>true</code>여야 함)</li><li><strong>발신자 허용 목록</strong>: 채널별 목록이 있는 <code>tools.elevated.allowFrom</code></li><li><strong>에이전트별 게이트</strong>: <code>agents.list[].tools.elevated.enabled</code> (더 제한만 가능)</li><li><strong>에이전트별 허용 목록</strong>: <code>agents.list[].tools.elevated.allowFrom</code> (발신자가 전역 + 에이전트별 모두 일치해야 함)</li><li><strong>Discord 폴백</strong>: <code>tools.elevated.allowFrom.discord</code>가 생략되면 <code>channels.discord.allowFrom</code>이 폴백으로 사용됨</li><li><strong>모든 게이트를 통과해야 합니다</strong>; 그렇지 않으면 엘리베이티드는 사용 불가로 처리됩니다</li></ul><p>허용 목록 항목 형식:</p><table tabindex="0"><thead><tr><th>접두사</th><th>매칭 대상</th></tr></thead><tbody><tr><td>(없음)</td><td>발신자 ID, E.164, 또는 From 필드</td></tr><tr><td><code>name:</code></td><td>발신자 표시 이름</td></tr><tr><td><code>username:</code></td><td>발신자 사용자명</td></tr><tr><td><code>tag:</code></td><td>발신자 태그</td></tr><tr><td><code>id:</code>, <code>from:</code>, <code>e164:</code></td><td>명시적 신원 타겟팅</td></tr></tbody></table><h2 id="엘리베이티드가-제어하지-않는-것" tabindex="-1">엘리베이티드가 제어하지 않는 것 <a class="header-anchor" href="#엘리베이티드가-제어하지-않는-것" aria-label="Permalink to &quot;엘리베이티드가 제어하지 않는 것&quot;">​</a></h2><ul><li><strong>도구 정책</strong>: <code>exec</code>가 도구 정책에 의해 거부된 경우 엘리베이티드가 재정의할 수 없습니다</li><li><strong>호스트 선택 정책</strong>: 엘리베이티드는 <code>auto</code>를 무료 크로스 호스트 재정의로 전환하지 않습니다. 구성된/세션 exec 대상 규칙을 사용하며 대상이 이미 <code>node</code>인 경우에만 <code>node</code>를 선택합니다.</li><li><strong><code>/exec</code>와 별개</strong>: <code>/exec</code> 지시어는 승인된 발신자를 위한 세션별 exec 기본값을 조정하며 엘리베이티드 모드가 필요하지 않습니다</li></ul><h2 id="관련-항목" tabindex="-1">관련 항목 <a class="header-anchor" href="#관련-항목" aria-label="Permalink to &quot;관련 항목&quot;">​</a></h2><ul><li><a href="/openclaw-docs-ko/tools/exec">Exec 도구</a> — 셸 명령 실행</li><li><a href="/openclaw-docs-ko/tools/exec-approvals">Exec 승인</a> — 승인 및 허용 목록 시스템</li><li><a href="/openclaw-docs-ko/gateway/sandboxing">샌드박싱</a> — 샌드박스 설정</li><li><a href="/openclaw-docs-ko/gateway/sandbox-vs-tool-policy-vs-elevated">샌드박스 vs 도구 정책 vs 엘리베이티드</a></li></ul>`,24)])])}const g=o(l,[["render",c]]);export{u as __pageData,g as default};
